<template>  <div class="fs-settlement-page art-full-height">    <div class="fs-page-header">      <div>        <div class="fs-page-title">结算单管理</div>        <div class="fs-page-desc">管理服务费结算单与残值结算单，支持审核流转与支付确认</div>      </div>      <div class="fs-page-actions">        <ElButton          style="color: #fff; background: #722ed1; border-color: #722ed1"          @click="openCreate('残值结算单')"        >          + 新建残值结算单申请        </ElButton>        <ElButton type="primary" @click="openCreate('服务费结算单')">          + 新建服务费结算单申请        </ElButton>      </div>    </div>    <ElCard shadow="never" class="fs-tab-card" :body-style="{ padding: 0 }">      <div class="fs-nav-tabs">        <button          v-for="tab in SETTLEMENT_BILL_NAV_TABS"          :key="tab.key"          type="button"          class="fs-nav-tab"          :class="{ 'is-active': activeTab === tab.key }"          @click="switchTab(tab.key)"        >          {{ tab.label }}          <span class="fs-tab-count">{{ tabCounts[tab.key] ?? 0 }}</span>        </button>      </div>    </ElCard>    <SettlementSearch      :search-form="searchForm"      :show-status-quick="activeTab === 'all'"      :exporting="exporting"      @search="handleSearch"      @reset="handleReset"      @export="handleExport"    />    <div class="fs-list-page">      <ElCard        class="fs-table-card art-table-card"        shadow="never"        :body-style="{ padding: 0, paddingBottom: '20px' }"      >        <ArtTable          :loading="loading"          :data="data"          :columns="columns"          :pagination="pagination"          :show-table-header="false"          :stripe="false"          row-key="id"          @pagination:size-change="handleSizeChange"          @pagination:current-change="handleCurrentChange"        />      </ElCard>    </div>    <SettlementDetailDialog v-model:visible="detailVisible" :bill-id="detailBillId" />    <SettlementApproveDialog      v-model:visible="approveVisible"      :row="actionRow"      @success="onActionSuccess"    />    <SettlementPayDialog v-model:visible="payVisible" :row="actionRow" @success="onActionSuccess" />    <SettlementCreateDialog      v-model:visible="createVisible"      :bill-type="createType"      @success="onActionSuccess"    />  </div></template><script setup lang="ts">  import * as XLSX from 'xlsx'  import { ElMessage } from 'element-plus'  import {    fetchSettlementBillExport,    fetchSettlementBillList,    fetchSettlementBillTabCounts  } from '@/api/recycle/finance-settlement.mock'  import type { ColumnOption } from '@/types/component'  import { useTable } from '@/hooks/core/useTable'  import type {    SettlementBillItem,    SettlementBillNavTab,    SettlementBillSearchParams,    SettlementBillType  } from '@/types/recycle/finance-settlement'  import {    SETTLEMENT_BILL_NAV_TABS,    SETTLEMENT_BILL_STATUS_CONFIG,    SETTLEMENT_BILL_TYPE_CONFIG  } from '@/types/recycle/finance-settlement'  import ArtSvgIcon from '@/components/core/base/art-svg-icon/index.vue'  import SettlementSearch from './modules/settlement-search.vue'  import SettlementDetailDialog from './modules/settlement-detail-dialog.vue'  import SettlementApproveDialog from './modules/settlement-approve-dialog.vue'  import SettlementPayDialog from './modules/settlement-pay-dialog.vue'  import SettlementCreateDialog from './modules/settlement-create-dialog.vue'  defineOptions({ name: 'RecycleFinanceSettlement' })  const activeTab = ref<SettlementBillNavTab>('all')  const tabCounts = ref<Record<SettlementBillNavTab, number>>({    all: 0,    待审核: 0,    审核通过: 0,    审核不通过: 0,    待付款: 0  })  const searchForm = ref<SettlementBillSearchParams>({    nav_tab: 'all',    status_quick: 'all',    salesman: '',    order_keyword: '',    applicant: '',    apply_start: '',    apply_end: '',    settlement_type: ''  })  const detailVisible = ref(false)  const detailBillId = ref<string | null>(null)  const approveVisible = ref(false)  const payVisible = ref(false)  const actionRow = ref<SettlementBillItem | null>(null)  const createVisible = ref(false)  const createType = ref<SettlementBillType | null>(null)  const exporting = ref(false)  function renderTypeTag(row: SettlementBillItem) {    const cfg = SETTLEMENT_BILL_TYPE_CONFIG[row.settlement_type]    return h(      'span',      { class: 'fs-tag', style: { color: cfg.color, background: cfg.bg } },      cfg.label    )  }  function renderStatusTag(row: SettlementBillItem) {    const cfg = SETTLEMENT_BILL_STATUS_CONFIG[row.status]    return h(      'span',      { class: 'fs-tag', style: { color: cfg.color, background: cfg.bg } },      cfg.label    )  }  function openDetail(row: SettlementBillItem) {    detailBillId.value = row.id    detailVisible.value = true  }  function openApprove(row: SettlementBillItem) {    actionRow.value = row    approveVisible.value = true  }  function openPay(row: SettlementBillItem) {    actionRow.value = row    payVisible.value = true  }  function openCreate(type: SettlementBillType) {    createType.value = type    createVisible.value = true  }  function buildColumns(): ColumnOption<SettlementBillItem>[] {    return [      {        prop: 'index',        label: '序号',        width: 60,        align: 'center',        formatter: (_row, _col, _cell, index) =>          String((pagination.current - 1) * pagination.size + (index ?? 0) + 1)      },      {        prop: 'contract_no',        label: '合同编号',        minWidth: 130,        formatter: (row) =>          h(            'a',            {              href: 'javascript:void(0)',              class: 'order-no',              onClick: () => openDetail(row)            },            row.contract_no          )      },      {        prop: 'settlement_type',        label: '结算单类型',        minWidth: 120,        formatter: (row) => renderTypeTag(row)      },      { prop: 'charge_type', label: '收费类型', minWidth: 100 },      { prop: 'applicant', label: '申请人', minWidth: 90 },      { prop: 'apply_time', label: '申请时间', minWidth: 150 },      {        prop: 'status',        label: '结算状态',        minWidth: 100,        formatter: (row) => renderStatusTag(row)      },      {        prop: 'reviewer_settle',        label: '审核人',        minWidth: 90,        formatter: (r) => r.reviewer_settle || '—'      },      {        prop: 'review_time_settle',        label: '审核时间',        minWidth: 140,        formatter: (r) => r.review_time_settle || '—'      },      {        prop: 'finance_remark',        label: '财务备注',        minWidth: 120,        formatter: (r) => r.finance_remark || '—'      },      {        prop: 'amount',        label: '结算金额(元)',        minWidth: 110,        formatter: (row) => h('span', { class: 'fs-amount' }, row.amount.toLocaleString())      },      {        prop: 'operation',        label: '操作',        width: 240,        fixed: 'right',        align: 'center',        formatter: (row) => {          const buttons = [            h(              'button',              {                type: 'button',                class: 'order-action-btn default',                onClick: () => openDetail(row)              },              [h(ArtSvgIcon, { icon: 'ri:eye-line', class: 'order-action-icon' }), '详情']            )          ]          if (row.status === '待审核') {            buttons.push(              h(                'button',                {                  type: 'button',                  class: 'order-action-btn primary',                  onClick: () => openApprove(row)                },                [                  h(ArtSvgIcon, { icon: 'ri:checkbox-circle-line', class: 'order-action-icon' }),                  '审核'                ]              )            )          }          if (row.status === '待付款') {            buttons.push(              h(                'button',                {                  type: 'button',                  class: 'order-action-btn warning',                  onClick: () => openPay(row)                },                [                  h(ArtSvgIcon, { icon: 'ri:upload-2-line', class: 'order-action-icon' }),                  '上传凭证'                ]              )            )          }          return h('div', { class: 'order-actions' }, buttons)        }      }    ]  }  const {    columns,    data,    loading,    pagination,    getData,    replaceSearchParams,    resetSearchParams,    handleSizeChange,    handleCurrentChange,    refreshData  } = useTable({    core: {      apiFn: fetchSettlementBillList,      apiParams: {        ...searchForm.value,        page: 1,        limit: 10      },      paginationKey: { current: 'page', size: 'limit' },      columnsFactory: () => buildColumns()    }  })  async function loadTabCounts() {    tabCounts.value = await fetchSettlementBillTabCounts()  }  function syncApiParams(extra?: Partial<SettlementBillSearchParams>) {    replaceSearchParams({      ...searchForm.value,      nav_tab: activeTab.value,      ...extra    })  }  function switchTab(tab: SettlementBillNavTab) {    activeTab.value = tab    searchForm.value.nav_tab = tab    if (tab !== 'all') searchForm.value.status_quick = 'all'    syncApiParams()    getData()  }  function handleSearch(form: SettlementBillSearchParams) {    searchForm.value = { ...form, nav_tab: activeTab.value }    syncApiParams()    getData()  }  function handleReset() {    searchForm.value = {      nav_tab: activeTab.value,      status_quick: 'all',      salesman: '',      order_keyword: '',      applicant: '',      apply_start: '',      apply_end: '',      settlement_type: ''    }    resetSearchParams()    syncApiParams()    getData()  }  async function onActionSuccess() {    await loadTabCounts()    refreshData()  }  async function handleExport() {    exporting.value = true    try {      const list = await fetchSettlementBillExport({        ...searchForm.value,        nav_tab: activeTab.value      })      if (!list.length) {        ElMessage.warning('暂无数据可导出')        return      }      const sheet = XLSX.utils.json_to_sheet(list)      const book = XLSX.utils.book_new()      XLSX.utils.book_append_sheet(book, sheet, '结算单')      XLSX.writeFile(book, `结算单_${new Date().toISOString().slice(0, 10)}.xlsx`)      ElMessage.success('导出成功')    } finally {      exporting.value = false    }  }  onMounted(() => {    loadTabCounts()  })</script><style lang="scss">  @use './settlement';</style>